1	import { mkdir, readFile, rename, unlink, writeFile } from "node:fs/promises";
2	import path from "node:path";
3	
4	/**
5	 * Windows-friendly rename: on NTFS, `rename()` can transiently fail with
6	 * EPERM/EBUSY when the target file is briefly held open by another
7	 * reader (antivirus, indexer, or even our own just-closed readFile on a
8	 * slow GC). POSIX fs do not exhibit this. Retry with exponential backoff
9	 * up to ~500ms, matching what git / electron-builder / pnpm do on
10	 * Windows.
11	 *
12	 * Non-Windows: single attempt, no retry needed.
13	 */
14	async function renameWithWindowsRetry(
15	  tmpPath: string,
16	  targetPath: string,
17	): Promise<void> {
18	  if (process.platform !== "win32") {
19	    await rename(tmpPath, targetPath);
20	    return;
21	  }
22	  const delays = [0, 10, 25, 50, 100, 150, 200]; // sum ≈ 535ms
23	  let lastErr: unknown;
24	  for (const d of delays) {
25	    if (d > 0) await new Promise((r) => setTimeout(r, d));
26	    try {
27	      await rename(tmpPath, targetPath);
28	      return;
29	    } catch (err: any) {
30	      if (err?.code !== "EPERM" && err?.code !== "EBUSY") throw err;
31	      lastErr = err;
32	    }
33	  }
34	  throw lastErr;
35	}
