37	/**
38	 * Shared atomic JSON helper for bridge state files (.usage.json,
39	 * goal-state/*.json, and any future small per-state JSON).
40	 *
41	 * Design goals, aligned with how schedule-store.ts already behaves:
42	 *
43	 *   1. Corruption tolerance: ENOENT and malformed-JSON cases return a
44	 *      caller-supplied default instead of throwing. Bridge stays up.
45	 *   2. Concurrent-write safety: writes to the same path are serialized
46	 *      via a per-path `writePending` promise chain so overlapping
47	 *      write() calls never interleave bytes on disk.
48	 *   3. Crash-safe atomicity: writes go to "<path>.tmp-<pid>-<ts>" and
49	 *      are then `rename()`'d into place. On NTFS/ext4/APFS same-volume
50	 *      rename is atomic — readers see either the old content or the new,
51	 *      never a half-written file.
52	 *
53	 * Not a goal: cross-process locking. The bridge runs as a single
54	 * process; the serialization here handles in-process races. If two
55	 * bridges pointed at the same SKILL_DIR run simultaneously, last
56	 * writer wins — we do not protect against that.
57	 */
58	
59	/** In-process serialization map: filePath → pending write chain. */
60	const writePendingByPath = new Map<string, Promise<void>>();
61	
62	/**
63	 * Read a JSON file. ENOENT and parse errors return `fallback()` without
64	 * throwing — the caller decides what "empty" means (empty object,
65	 * default schema, etc.).
66	 *
67	 * Malformed-JSON case is logged (console.error) so silent data loss is
68	 * visible in the bridge log, but the call still succeeds.
69	 */
70	export async function readJsonOrDefault<T>(
71	  filePath: string,
72	  fallback: () => T,
73	): Promise<T> {
74	  let raw: string;
75	  try {
76	    raw = await readFile(filePath, "utf8");
77	  } catch (err: any) {
78	    if (err?.code === "ENOENT") return fallback();
79	    throw err;
80	  }
81	  if (raw.trim() === "") return fallback();
82	  try {
83	    return JSON.parse(raw) as T;
84	  } catch (err) {
85	    console.error(
86	      `[atomicJson] ${filePath} is not valid JSON; returning fallback. ` +
87	        `Error: ${(err as Error).message}`,
88	    );
89	    return fallback();
90	  }
91	}
92	
93	/**
94	 * Atomically write `data` as pretty-printed JSON to `filePath`.
95	 *
96	 * Steps:
97	 *   1. Ensure parent dir exists (mkdir recursive).
98	 *   2. Write to "<filePath>.tmp-<pid>-<timestamp>".
99	 *   3. rename() the tmp file over the target. Same-volume rename is
100	 *      atomic on NTFS / POSIX fs.
101	 *
102	 * Concurrent calls for the same `filePath` are serialized via an
103	 * in-process promise chain so tmp files don't collide and we never
104	 * observe a torn write.
105	 *
106	 * Errors during step 2/3 are propagated; the caller decides whether to
107	 * retry or surface to the user. On step-3 failure we best-effort
108	 * unlink() the orphan tmp file so /tmp doesn't fill up over time.
109	 */
110	export async function atomicWriteJson(
111	  filePath: string,
112	  data: unknown,
113	): Promise<void> {
114	  const absPath = path.resolve(filePath);
115	  const prev = writePendingByPath.get(absPath) ?? Promise.resolve();
116	  const next = prev.then(async () => {
117	    await mkdir(path.dirname(absPath), { recursive: true });
118	    const tmpPath = `${absPath}.tmp-${process.pid}-${Date.now()}`;
119	    const body = JSON.stringify(data, null, 2) + "\n";
120	    try {
121	      await writeFile(tmpPath, body, "utf8");
122	      await renameWithWindowsRetry(tmpPath, absPath);
123	    } catch (err) {
124	      // Best-effort cleanup; ignore failures since tmpPath may not exist.
125	      await unlink(tmpPath).catch(() => {});
126	      throw err;
127	    }
128	  });
129	  // Attach a catch so an earlier failure doesn't poison subsequent writes:
130	  // each caller awaits its own `next`, but the chain's `prev` for future
131	  // writers should resolve either way.
132	  writePendingByPath.set(
133	    absPath,
134	    next.catch((err) => {
135	      console.error(`[atomicJson] atomicWriteJson(${absPath}) failed:`, err);
136	    }),
137	  );
138	  await next;
139	}
140	
141	/**
142	 * Small convenience for code that reads, mutates, and writes back under
143	 * the same serialization guarantee. The `update()` callback runs inside
144	 * the write chain, so concurrent update() calls on the same path are
145	 * serialized read-modify-write — no lost-update race.
146	 *
147	 * `initial` is used when the file does not exist or is malformed.
148	 */
149	export async function updateJson<T>(
150	  filePath: string,
151	  initial: () => T,
152	  update: (current: T) => T | Promise<T>,
153	): Promise<T> {
154	  const absPath = path.resolve(filePath);
155	  const prev = writePendingByPath.get(absPath) ?? Promise.resolve();
156	  let result: T;
157	  const next = prev.then(async () => {
158	    const current = await readJsonOrDefault<T>(absPath, initial);
159	    const updated = await update(current);
160	    result = updated;
161	    await mkdir(path.dirname(absPath), { recursive: true });
162	    const tmpPath = `${absPath}.tmp-${process.pid}-${Date.now()}`;
163	    const body = JSON.stringify(updated, null, 2) + "\n";
164	    try {
165	      await writeFile(tmpPath, body, "utf8");
166	      await renameWithWindowsRetry(tmpPath, absPath);
167	    } catch (err) {
168	      await unlink(tmpPath).catch(() => {});
169	      throw err;
170	    }
171	  });
172	  writePendingByPath.set(
173	    absPath,
174	    next.catch((err) => {
175	      console.error(`[atomicJson] updateJson(${absPath}) failed:`, err);
176	    }),
177	  );
178	  await next;
179	  // Non-null assertion is safe: if `next` resolved, `result` was assigned.
180	  return result!;
181	}
