146	/** After a wiki page is written, scan it and inject [[wikilinks]] for known entities. */
147	function applyAutoWikilink(slug: string): void {
148	  const { MEMORY_DIR } = deps();
149	  for (const sub of ["queries", "concepts", "references", "lessons", "tasks"]) {
150	    const filePath = path.join(MEMORY_DIR, "wiki", sub, `${slug}.md`);
151	    if (existsSync(filePath)) {
152	      try {
153	        const content = readFileSync(filePath, "utf8");
154	        const linked = autoWikilink(content);
155	        if (linked !== content) {
156	          writeFileSync(filePath, linked, "utf8");
157	          console.log(`[auto-wikilink] injected links into wiki/${sub}/${slug}.md`);
158	        }
159	      } catch (err) {
160	        console.error(`[auto-wikilink] failed for ${slug}:`, err);
161	      }
162	      return;
163	    }
164	  }
165	}
