167	// ─── Orphan turn flusher ──────────────────────────────────────────────────────
168	//
169	// Delivers agent output that arrived with NO active prompt turn — e.g. a
170	// Claude Code harness background sub-agent completes and re-invokes the agent
171	// via task-notification, producing an agent_message_chunk while runPrompt's
172	// request→response flush path isn't listening (see SPEC-orphan-turn-flusher).
173	//
174	// SessionManager buffers + debounces those chunks and calls this on quiescence
175	// (wired via sessions.onOrphanTurn in index.ts). This reuses the SAME reply
176	// transform (transformReplyTokens) + render/split helpers as the normal turn —
177	// there is deliberately NO second transform. Tokens that only make sense inside
178	// a live turn (GOAL_DONE / RESTART / CONTINUE / WIKI_QUERY / SKILL_PROPOSE /
179	// SPECIALIST_PROXY / relay*) are intentionally ignored here; user-facing tokens
180	// (text / SEND_FILE / ASK / SCHEDULE / STICKER) are delivered.
181	export async function flushOrphanTurn(session: ChatSession, rawText: string): Promise<void> {
182	  const { bot, rateLimitedUntil, queuePendingMessage, scheduler, scheduleStore } = deps();
183	  const chatId = session.chatId;
184	
185	  // Dedup: skip content already delivered (e.g. same summary that also came
186	  // through a normal turn, or a duplicate orphan flush). Shares the 5-min
187	  // window used by specialist/parallel result injection.
188	  if (isDuplicateResult(chatId, rawText)) {
189	    console.log(`[orphan ${chatId}] skipped (dedup hit)`);
190	    return;
191	  }
192	
193	  const ab7 = transformReplyTokens(rawText, {
194	    parseDuration,
195	    parseAbsoluteTime,
196	    parseRecurrence,
197	    computeNextRunAt,
198	  });
199	
200	  // SCHEDULE tokens — register the same way the normal path does.
201	  const scheduleReceipts: string[] = [];
202	  for (const se of ab7.scheduleTokens) {
203	    try {
204	      const entry = await scheduleStore.add({
205	        chatId,
206	        userId: session.userId ?? chatId,
207	        runAt: se.runAt,
208	        prompt: se.prompt,
209	        recurrence: se.recurrence,
210	      });
211	      scheduler.arm(entry);
212	      const delta = formatRelative(se.runAt - Date.now());
213	      const recurTag = se.recurrence ? ` [${formatRecurrence(se.recurrence)}]` : "";
214	      scheduleReceipts.push(
215	        `⏰ 已排程 ${entry.id}${recurTag}，${delta} 後觸發（${new Date(se.runAt).toLocaleString()}）`,
216	      );
217	    } catch (err) {
218	      console.error(`[orphan ${chatId}] schedule token register failed:`, err);
219	    }
220	  }
221	
222	  // Surface (but don't act on) tokens that require live-turn context.
223	  const ignored: string[] = [];
224	  if (ab7.goalDone) ignored.push("GOAL_DONE");
225	  if (ab7.restartToken) ignored.push("RESTART");
226	  if (ab7.continueToken) ignored.push("CONTINUE");
227	  if (ab7.wikiQuery) ignored.push("WIKI_QUERY");
228	  if (ab7.skillPropose) ignored.push("SKILL_PROPOSE");
229	  if (ab7.specialistProxy) ignored.push("SPECIALIST_PROXY");
230	  if (ab7.moaPlan) ignored.push("MOA_PLAN");
231	  if (ignored.length) {
232	    console.log(`[orphan ${chatId}] ignoring turn-context token(s): ${ignored.join(", ")}`);
233	  }
234	
235	  const body = scheduleReceipts.length
236	    ? (ab7.text ? `${ab7.text}\n\n${scheduleReceipts.join("\n")}` : scheduleReceipts.join("\n"))
237	    : ab7.text;
238	  const askKeyboard = buildAskKeyboard(ab7.askTokens);
239	
240	  // Text delivery (chunked). Rate-limit aware: queue for replay if throttled.
241	  if (body.trim().length > 0) {
242	    const chunks = splitForTelegram(body);
243	    for (let i = 0; i < chunks.length; i++) {
244	      const isLast = i === chunks.length - 1;
245	      const pageTag = chunks.length > 1 ? `(${i + 1}/${chunks.length})\n` : "";
246	      const text = pageTag + chunks[i];
247	      const extra = isLast && askKeyboard ? { reply_markup: askKeyboard } : undefined;
248	      if (rateLimitedUntil() > Date.now()) {
249	        queuePendingMessage(chatId, text);
250	        continue;
251	      }
252	      try {
253	        const msg = await bot.api.sendMessage(chatId, text, extra);
254	        if (isLast && askKeyboard && msg?.message_id !== undefined) {
255	          askRegistry.set(msg.message_id, ab7.askTokens);
256	        }
257	      } catch (err) {
258	        console.error(`[orphan ${chatId}] chunk send failed, queueing for replay:`, err);
259	        queuePendingMessage(chatId, text);
260	      }
261	      if (!isLast) await new Promise<void>((r) => setTimeout(r, 1100));
262	    }
263	  } else if (askKeyboard) {
264	    // ASK-only orphan turn (rare) — carry the keyboard on a minimal message.
265	    try {
266	      const msg = await bot.api.sendMessage(chatId, "（背景任務完成）", { reply_markup: askKeyboard });
267	      if (msg?.message_id !== undefined) askRegistry.set(msg.message_id, ab7.askTokens);
268	    } catch (err) {
269	      console.error(`[orphan ${chatId}] ask-only send failed:`, err);
270	    }
271	  }
272	
273	  // SEND_FILE — sendFilesByPaths needs a Context-like; build a minimal shim.
274	  if (ab7.sendFiles.length > 0) {
275	    const fakeCtx = {
276	      chat: { id: chatId, type: "private" as const },
277	      replyWithPhoto: (f: unknown, extra?: unknown) => bot.api.sendPhoto(chatId, f as any, extra as any),
278	      replyWithDocument: (f: unknown, extra?: unknown) => bot.api.sendDocument(chatId, f as any, extra as any),
279	    } as unknown as Context;
280	    try {
281	      await sendFilesByPaths(fakeCtx, ab7.sendFiles);
282	    } catch (err) {
283	      console.error(`[orphan ${chatId}] sendFilesByPaths failed:`, err);
284	    }
285	  }
286	
287	  // Stickers
288	  for (const emotion of ab7.stickerEmotions) {
289	    const fileId = STICKER_MAP[emotion];
290	    if (!fileId) continue;
291	    try {
292	      await bot.api.sendSticker(chatId, fileId);
293	    } catch (err) {
294	      console.warn(`[orphan ${chatId}] sticker ${emotion} failed — ${(err as Error).message}`);
295	    }
296	  }
297	
298	  console.log(
299	    `[orphan ${chatId}] delivered (textChars=${body.length}, files=${ab7.sendFiles.length}, ` +
300	      `asks=${ab7.askTokens.length}, schedules=${scheduleReceipts.length}, stickers=${ab7.stickerEmotions.length})`,
301	  );
302	}
