304	// ─── runPrompt ────────────────────────────────────────────────────────────────
305	
306	export async function runPrompt(
307	  ctx: Context,
308	  session: ChatSession,
309	  text: string,
310	  mode: RunPromptMode = { kind: "user" },
311	) {
312	  const { bot, sessions, rateLimitedUntil, onRateLimitRecovery, queuePendingMessage,
313	    handleRestart, STREAM_EDIT_INTERVAL_MS, MEMORY_DIR, scheduler, scheduleStore } = deps();
314	
315	  const continuationContext: ContinuationContext | undefined =
316	    mode.kind === "continuation" ? mode.context : undefined;
317	  const isMeta = mode.kind === "meta";
318	  const isSilentMeta = mode.kind === "meta" && mode.silent === true;
319	  const relayReplyTo = mode.kind === "relay" ? mode.replyTo : undefined;
320	  const isRelay = mode.kind === "relay";
321	  // Optional header prepended to the visible reply (and shown in the "Thinking…"
322	  // placeholder). Used e.g. by ASK button clicks to record "我選擇了：X" in the
323	  // reply itself, so the original button message isn't rewritten and no extra
324	  // message is sent. Render-only — NOT added to agent history/memory.
325	  const replyHeader = mode.kind === "user" ? mode.replyHeader : undefined;
326	  const chatId = ctx.chat!.id;
327	
328	  // Guard against concurrent prompts on the same ACP session.
329	  if (session.inflight) {
330	    if (relayReplyTo) {
331	      sendRelay(relayReplyTo, "小X 目前上一輪還在處理中，稍後再回覆。").catch((err) =>
332	        console.error(`[chat ${chatId}] relay busy notice to ${relayReplyTo} failed:`, err),
333	      );
334	      notifyRelayOwner(
335	        bot,
336	        config.allowedUserIds[0] ?? 0,
337	        `⏳ 「${relayReplyTo}」又送來 relay 訊息，但上一輪還在處理中，已擋掉這次重複注入。`,
338	        `busy notice for ${relayReplyTo}`,
339	      );
340	      return;
341	    }
