208	// ───────────────────────────────────────────────────────────────────────
209	// Code-region masking
210	// ───────────────────────────────────────────────────────────────────────
211	// Ported verbatim from index.ts's existing maskCodeRegions so refactor is
212	// behavior-preserving. Sentinel uses null bytes so nothing in normal text
213	// can collide with it.
214	const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
215	
216	function maskCodeRegions(text: string): {
217	  masked: string;
218	  restore: (s: string) => string;
219	} {
220	  const slots: string[] = [];
221	  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
222	    const idx = slots.length;
223	    slots.push(m);
224	    return `\u0000CODE${idx}\u0000`;
225	  });
226	  const restore = (s: string) =>
227	    s.replace(CODE_PLACEHOLDER_RE, (_m, i: string) => slots[Number(i)] ?? "");
228	  return { masked, restore };
229	}
