231	// ───────────────────────────────────────────────────────────────────────
232	// ASK parsing (moved from index.ts verbatim — behavior preserved)
233	// ───────────────────────────────────────────────────────────────────────
234	function parseAskInner(inner: string): AskEntry | null {
235	  const reject = (reason: string): null => {
236	    const preview = inner.length > 80 ? `${inner.slice(0, 77)}...` : inner;
237	    console.warn(`[ASK] malformed token rejected: ${reason} | inner="${preview}"`);
238	    return null;
239	  };
240	  const parts = inner.split("|").map((s) => s.trim());
241	  if (parts.length < 2) return reject("need at least question_id + 1 option");
242	  const questionId = parts[0];
243	  if (!ASK_ID_RE.test(questionId)) {
244	    return reject(
245	      `question_id "${questionId}" invalid (need [a-zA-Z0-9_-]{1,32}, got length ${questionId.length})`,
246	    );
247	  }
248	  const options: AskOption[] = [];
249	  const keys = new Set<string>();
250	  let recommendedCount = 0;
251	  for (const raw of parts.slice(1)) {
252	    if (!raw) continue;
253	    let spec = raw;
254	    let recommended = false;
255	    if (spec.startsWith("*")) {
256	      recommended = true;
257	      spec = spec.slice(1);
258	    }
259	    const eq = spec.indexOf("=");
260	    if (eq <= 0) return reject(`option "${raw}" missing "key=label"`);
261	    const key = spec.slice(0, eq).trim();
262	    const label = spec.slice(eq + 1).trim();
263	    if (!ASK_KEY_RE.test(key)) {
264	      return reject(
265	        `key "${key}" invalid (need [a-zA-Z0-9_-]{1,20}, got length ${key.length})`,
266	      );
267	    }
268	    if (!label) return reject(`key "${key}" has empty label`);
269	    if (label.length > ASK_LABEL_SOFT && label.length <= ASK_LABEL_MAX) {
270	      // Soft-cap warning only; see ASK_LABEL_SOFT definition above for rationale.
271	      console.warn(
272	        `[ASK] label soft cap exceeded (got ${label.length}, soft ${ASK_LABEL_SOFT}): key="${key}" label="${label}"`,
273	      );
274	    }
275	    if (label.length > ASK_LABEL_MAX) {
276	      return reject(
277	        `key "${key}" label too long (got ${label.length}, max ${ASK_LABEL_MAX}): "${label}"`,
278	      );
279	    }
280	    if (keys.has(key)) return reject(`duplicate key "${key}"`);
281	    keys.add(key);
282	    if (recommended && recommendedCount > 0) recommended = false;
283	    if (recommended) recommendedCount++;
284	    options.push({ key, label, recommended });
285	  }
286	  if (options.length < 1) return reject("no valid options");
287	  if (options.length > 8) return reject(`too many options (got ${options.length}, max 8)`);
288	  return { questionId, options };
289	}
