45	function maskCodeRegionsForRelayCapture(text: string): { masked: string; restore: (s: string) => string } {
46	  const slots: string[] = [];
47	  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
48	    const idx = slots.length;
49	    slots.push(m);
50	    return `\u0000CODE${idx}\u0000`;
51	  });
52	  const restore = (s: string) =>
53	    s.replace(CODE_PLACEHOLDER_RE, (_m, i: string) => slots[Number(i)] ?? "");
54	  return { masked, restore };
55	}
