57	export function isRelayDelegatePlaceholderGoal(goal: string): boolean {
58	  const g = goal.trim();
59	  return g === "" || g === "..." || g === "…" || /^<[^>\r\n]*>?$/.test(g);
60	}
61	
62	export function captureRelayDelegateTokensFromText(buffer: string, existing: string[] = []): string[] {
63	  const next = [...existing];
64	  const { masked, restore } = maskCodeRegionsForRelayCapture(buffer);
65	  let m: RegExpExecArray | null;
66	  RELAY_DELEGATE_RE.lastIndex = 0;
67	  while ((m = RELAY_DELEGATE_RE.exec(masked)) !== null) {
68	    const goal = m[2]?.trim() ?? "";
69	    if (isRelayDelegatePlaceholderGoal(goal)) continue;
70	    const token = restore(m[0]);
71	    if (!next.includes(token)) next.push(token);
72	  }
73	  return next;
74	}
