101	export interface ToolEvent {
102	  /** ACP toolCallId when present, else a synthetic id for matching updates. */
103	  id: string;
104	  /** Human-readable tool name/title. */
105	  name: string;
106	  status: "running" | "completed" | "failed";
107	  /** Date.now() at tool_call start. */
108	  startedAt: number;
