119	/**
120	 * Mark a running tool as completed/failed, stamping elapsed time. Matches by
121	 * ACP toolCallId; if the update carries no id (or none matches), falls back to
122	 * the most recent still-running entry so the line still transitions.
123	 */
124	function markToolDone(
125	  session: ChatSession,
126	  updId: string | undefined,
127	  status: "completed" | "failed",
128	): void {
129	  let entry = updId
130	    ? session.toolTimeline.find((t) => t.id === updId && t.status === "running")
131	    : undefined;
132	  if (!entry) {
133	    for (let i = session.toolTimeline.length - 1; i >= 0; i--) {
134	      if (session.toolTimeline[i].status === "running") {
135	        entry = session.toolTimeline[i];
136	        break;
137	      }
138	    }
139	  }
140	  if (entry) {
141	    entry.status = status;
142	    entry.elapsedMs = Date.now() - entry.startedAt;
143	  }
144	}
