146	/**
147	 * Lines shown as the tool-progress prefix of the streamed reply: one line per
148	 * tool (latest 5) as `<emoji> <name> (<secs>s)`, followed by any advisory
149	 * lines (reflexion hints) carried in {@link ChatSession.toolLog}.
150	 */
151	// Tool 行是進度指示器不是審計記錄：title 是 adapter 原文（可能是整條
152	// Bash 命令或絕對路徑，甚至含換行），render 層單行化 + 截斷；
153	// toolTimeline 保留原始資料不加工。
154	const TOOL_LINE_NAME_MAX = 64;
155	
156	export function toolPrefixLines(session: ChatSession): string[] {
157	  const lines = session.toolTimeline.slice(-5).map((t) => {
158	    const secs =
159	      t.status !== "running" && t.elapsedMs !== undefined
160	        ? ` (${(t.elapsedMs / 1000).toFixed(1)}s)`
161	        : "";
162	    let name = t.name.replace(/\s*[\r\n]+\s*/g, " ");
163	    if (name.length > TOOL_LINE_NAME_MAX) {
164	      name = name.slice(0, TOOL_LINE_NAME_MAX - 1) + "…";
165	    }
166	    return `${TOOL_STATUS_EMOJI[t.status]} ${name}${secs}`;
167	  });
168	  return [...lines, ...session.toolLog];
169	}
