549	  /** Factory: create the right Provider based on type. */
550	  private createProvider(type: ProviderType, env: Record<string, string>, systemPrompt?: string, backend?: AcpBackendDef, resumeSessionId?: string): Provider {
551	    if (type === "acp") {
552	      // With a pinned backend (/agent), its table entry replaces the .env
553	      // agent wholesale — including the model/effort pin (undefined = leave
554	      // the adapter's own default untouched, NOT fall back to .env's pin).
555	      return new AcpProvider({
556	        command: backend?.command ?? config.agent.command,
557	        args: backend?.args ?? config.agent.args,
558	        cwd: config.sessionCwd,
559	        env,
560	        promptRetries: config.acpPromptRetries,
561	        promptRetryBaseMs: config.acpPromptRetryBaseMs,
562	        acpModel: backend ? (backend.model ?? "") : config.acpModel,
563	        acpEffort: backend ? (backend.effort ?? "") : config.acpEffort,
564	        sessionCwd: config.sessionCwd,
565	        resumeSessionId,
566	      });
567	    }
568	    // All other types use DirectProvider
569	    const modelKey = type as keyof typeof config.models;
570	    const apiKeyKey = type as keyof typeof config.apiKeys;
571	    return new DirectProvider({
572	      type,
573	      model: config.models[modelKey] ?? config.models.local,
574	      baseUrl: resolveBaseUrl(type, config.ollamaUrl),
575	      apiKey: config.apiKeys[apiKeyKey] ?? "",
576	      systemPrompt,
577	      mcpEnv: env,
578	      // Local models have limited context — keep the server set focused.
579	      mcpServerFilter: type === "local" ? ["memory", "notebooklm", "google"] : undefined,
580	    });
581	  }
