584	   * Switch the active provider for a chat. Closes the old session and
585	   * creates a new one with the specified provider type.
586	   * Returns the new session.
587	   */
588	  async switchProvider(chatId: number, type: ProviderType, userId?: number): Promise<ChatSession> {
589	    const existing = this.sessions.get(chatId);
590	    if (existing) {
591	      this.sessions.delete(chatId);
592	      await existing.client.close().catch(() => {});
593	    }
594	    return this.create(chatId, userId, type);
595	  }
