597	  /**
598	   * Switch the ACP backend for a chat (/agent) with conversation handoff.
599	   * Reuses the full drop() close pipeline — archiveOnClose (substantive
600	   * guard + priorArchive carry-forward + LLM summary), onBeforeClose
601	   * (transcript + working-state) — so the new session's create() finds the
602	   * archive on disk and injects the handoff context into its preamble.
603	   * Throws when the backend key is unknown or a turn is in flight.
604	   */
605	  async switchAgent(chatId: number, backendKey: string, userId?: number): Promise<ChatSession> {
606	    const def = loadAcpProviders()[backendKey];
607	    if (!def) {
608	      throw new Error(`未知的 agent "${backendKey}"（不在 acp-providers.json）`);
609	    }
610	    const existing = this.sessions.get(chatId);
611	    if (existing?.inflight) {
612	      throw new Error("目前有 turn 進行中，請等它完成或先 /cancel 再切換");
613	    }
614	    if (existing) {
615	      await this.drop(chatId, "agent_switch");
616	    }
617	    this.acpBackendByChat.set(chatId, backendKey);
618	    savePinnedAgents(this.acpBackendByChat).catch((err) =>
619	      console.warn(`[session ${chatId}] failed to persist pinned agent:`, err),
620	    );
621	    return this.create(chatId, userId, "acp");
622	  }
