624	  /** Start (or restart) the inactivity timer for a turn. */
625	  startInactivityTimer(session: ChatSession) {
626	    this.clearInactivityTimer(session);
627	    const ms = session._toolInFlight && config.turnToolInactivityTimeoutMs > 0
628	      ? config.turnToolInactivityTimeoutMs
629	      : config.turnInactivityTimeoutMs;
630	    if (ms <= 0) return;
631	    session._inactivityTimer = setTimeout(() => {
632	      console.warn(
