652	  private applyUpdate(session: ChatSession, u: SessionUpdate) {
653	    this.resetInactivityTimer(session);
654	    const up = u.update;
655	    // Opportunistically capture usage-like meta the agent may attach.
656	    const meta = (up as { _meta?: Record<string, unknown> })._meta;
657	    const usage =
658	      (meta?.usage as Record<string, unknown> | undefined) ??
659	      ((up as { usage?: Record<string, unknown> }).usage);
660	    if (usage && typeof usage === "object") {
661	      session.usage = usage;
662	    }
663	    switch (up.sessionUpdate) {
664	      case "agent_message_chunk":
665	      case "agent_thought_chunk": {
666	        const content = up.content as { type?: string; text?: string } | undefined;
667	        if (content?.type === "text" && typeof content.text === "string") {
668	          // Orphan turn: a message chunk arrived with no prompt turn in-flight
669	          // (typically a background sub-agent completion re-invoking the agent
670	          // via task-notification). The normal request→response flush path in
671	          // runPrompt isn't listening, so route it to the debounced orphan
672	          // flusher instead of the live-turn buffer. Thought chunks are never
673	          // user-facing, so only real message chunks take this path.
674	          if (up.sessionUpdate === "agent_message_chunk" && !session.inflight) {
675	            this.appendOrphan(session, content.text);
676	            break;
677	          }
678	          const wasEmpty = session.buffer.length === 0 && !session.thinkingBuffer;
679	          if (up.sessionUpdate === "agent_thought_chunk") {
680	            session.thinkingBuffer = (session.thinkingBuffer || "") + content.text;
681	          } else {
682	            session.buffer += content.text;
683	            session.charsOut += content.text.length;
684	          }
685	          if (wasEmpty) petState("streaming");
686	          // Early-capture RELAY_DELEGATE tokens during streaming.
687	          // Workaround: Kiro CLI may strip <<...>> from final text in pure-text turns,
688	          // but streaming chunks arrive unfiltered. We capture complete tokens here
689	          // so the final-render path can fall back to them if normal extraction finds nothing.
690	          // Inline/fenced code examples must stay inert, matching final token extraction.
691	          const captured = captureRelayDelegateTokensFromText(session.buffer, session._streamingDelegates ?? []);
692	          session._streamingDelegates = captured.length ? captured : undefined;
693	          session.onUpdate?.(session);
694	        }
695	        break;
696	      }
697	      case "tool_call": {
698	        const title = (up.title as string) ?? "tool";
699	        const startId = up.toolCallId as string | undefined;
700	        if (startId) (session._toolTitles ??= new Map()).set(startId, title);
701	        session.toolTimeline.push({
