708	        session._recentToolNames = appendToolName(session._recentToolNames ?? [], title);
709	        session._toolInFlight = true;
710	        petState("tool", title);
711	        session.onUpdate?.(session);
712	        break;
713	      }
714	      case "tool_call_update": {
715	        const status = up.status as string | undefined;
716	        const updId = up.toolCallId as string | undefined;
717	        // tool_call_update 只帶 opaque toolCallId、不帶 name。用 tool_call 起始時
718	        // 綁定的 title 解析工具名；退而用 inline title，再退用 "tool"。
719	        const toolName =
720	          (updId ? session._toolTitles?.get(updId) : undefined) ??
721	          (up.title as string) ??
722	          "tool";
723	        if (status === "completed") {
724	          markToolDone(session, updId, "completed");
725	          // A success clears any stale reflexion hint (fail streak is over).
726	          if (session.toolLog.length) session.toolLog = [];
727	          session._toolInFlight = false;
728	          session._consecutiveToolFails = 0;
729	          logEvent("tool_call", { name: toolName, status: "completed" }, { chatId: session.chatId });
730	          // Tier A seq observation：僅 ACP 路徑（Direct 由 tool-loop 的 Tier B rich 接手，避免雙記 BC-1）。
731	          // slice(0,-1) 排除「當前工具自身」（tool_call 已先 push title），對齊 rich 的「preceding 不含本 tool」語意。
732	          if (session.activeProvider === "acp") {
733	            recordSeqObservation({
734	              name: toolName,
735	              status: "completed",
736	              sessionId: session.sessionId,
737	              chatId: session.chatId,
738	              precedingTools: (session._recentToolNames ?? []).slice(0, -1),
739	            });
740	          }
741	          if (updId) session._toolTitles?.delete(updId);
742	          session.onUpdate?.(session);
743	        } else if (status === "failed") {
744	          markToolDone(session, updId, "failed");
745	          session._toolInFlight = false;
746	          session._consecutiveToolFails++;
747	          logEvent("tool_call", { name: toolName, status: "failed" }, { chatId: session.chatId });
748	          // Tier A seq observation：僅 ACP 路徑（Direct 失敗 tool 由 tool-loop catch 分支寫 rich）。
749	          if (session.activeProvider === "acp") {
750	            recordSeqObservation({
751	              name: toolName,
752	              status: "failed",
753	              sessionId: session.sessionId,
754	              chatId: session.chatId,
755	              precedingTools: (session._recentToolNames ?? []).slice(0, -1),
756	            });
757	          }
758	          if (updId) session._toolTitles?.delete(updId);
759	          if (session._consecutiveToolFails >= 2) {
