781	  private appendOrphan(session: ChatSession, text: string) {
782	    if (config.orphanFlushQuiescenceMs <= 0) return;
783	    if (session._orphanSuppressUntil && Date.now() < session._orphanSuppressUntil) return;
784	    session._orphanBuffer = (session._orphanBuffer || "") + text;
785	    session.charsOut += text.length;
786	    if (session._orphanFlushTimer) clearTimeout(session._orphanFlushTimer);
787	    session._orphanFlushTimer = setTimeout(() => {
788	      session._orphanFlushTimer = undefined;
