843	  cancel(chatId: number) {
844	    const s = this.sessions.get(chatId);
845	    if (!s) return;
846	    s.client.cancel();
847	
848	    // Optimistic cancel: immediately free the session so the user can send
849	    // new messages without waiting for the CLI to acknowledge cancellation.
850	    s._cancelledTurn = true;
851	    s.inflight = false;
852	    s._toolInFlight = false;
853	    s.onUpdate = undefined;
854	    this.clearInactivityTimer(s);
855	    // Drop any orphan capture in progress: after cancel, inflight=false means
856	    // trailing chunks from the cancelled turn would flip to the orphan path.
857	    // A cancel means "stop, I don't want this" — discard rather than flush
858	    // abandoned partial output. Genuine later background output re-arms fresh.
859	    if (s._orphanFlushTimer) { clearTimeout(s._orphanFlushTimer); s._orphanFlushTimer = undefined; }
860	    s._orphanBuffer = undefined;
861	    // Suppress capture across the force-kill window so trailing chunks don't leak.
862	    s._orphanSuppressUntil = Date.now() + 20_000;
863	
864	    // Force-kill escalation: if CLI doesn't exit the turn within 15s,
865	    // kill the process tree and re-create on next message.
866	    if (!s.client.isClosed) {
867	      const timer = setTimeout(async () => {
868	        if (s.client.isClosed) return;
869	        console.warn(`[cancel] chat ${chatId} CLI still alive after 15s — force-killing`);
870	        await s.client.close();
871	      }, 15_000);
872	      timer.unref?.();
873	    }
874	  }
