1041	  private async sweepIdle() {
1042	    const now = Date.now();
1043	    for (const [chatId, s] of this.sessions) {
1044	      // --- Runtime Health Monitor ---
1045	      // Detect subprocess that silently died (pid no longer valid) but
1046	      // exit event hasn't fired yet (possible on Windows when parent shell
1047	      // exits but Node doesn't see the signal).
1048	      const clientPid = "pid" in s.client ? (s.client as { pid?: number }).pid : undefined;
1049	      if (!s.client.isClosed && clientPid !== undefined) {
1050	        try {
1051	          // process.kill(pid, 0) throws if pid doesn't exist — non-destructive probe
1052	          process.kill(clientPid, 0);
1053	        } catch {
1054	          // Process is gone but client didn't fire exit event
1055	          console.error(`[health] chat ${chatId}: ACP subprocess (pid=${clientPid}) is dead, forcing cleanup`);
1056	          logEvent("session_end", { reason: "health_monitor_dead_process" }, { chatId, userId: s.userId });
1057	          this.sessions.delete(chatId);
1058	          // Preserve context: archive what streamed, or carry the prior archive
1059	          // forward (it was already deleted from disk when this session started).
1060	          if (s.history.length > 0 || s.priorArchive) {
1061	            await this.archiveOnClose(s, "health_monitor");
1062	          }
1063	          s.client.close().catch(() => {});
1064	          if (this.onUnexpectedExit) {
1065	            this.onUnexpectedExit(s, null).catch((e) =>
1066	              console.error(`[health ${chatId}] onUnexpectedExit failed:`, e),
1067	            );
1068	          }
1069	          continue; // skip idle check for this session
1070	        }
1071	      }
1072	
1073	      // --- Idle timeout sweep ---
1074	      if (now - s.lastUsed > config.sessionIdleMs) {
1075	        console.log(`[session] dropping idle chat ${chatId}`);
1076	        this.sessions.delete(chatId);
1077	        // Archive session state before closing (summary + trivial carry-forward)
1078	        if (s.history.length > 0 || s.priorArchive) {
1079	          await this.archiveOnClose(s, "idle");
1080	        }
1081	        if (this.onBeforeClose) {
1082	          try { await this.onBeforeClose(s); } catch (e) {
1083	            console.error(`[session ${chatId}] onBeforeClose failed:`, e);
1084	          }
1085	        }
1086	        s.client.close().catch(() => {});
1087	      }
1088	    }
1089	  }
