37	    const sys32 = path.join(sysRoot, "System32");
38	    base.SystemRoot ??= sysRoot;
39	    base.COMSPEC ??= path.join(sys32, "cmd.exe");
40	    base.PATHEXT ??= ".COM;.EXE;.BAT;.CMD;.VBS;.VBE;.JS;.JSE;.WSF;.WSH;.MSC;.PS1";
41	    // Merge registry PATH entries into the runtime PATH (don't replace —
42	    // runtime PATH may include npm/Kiro-Cli dirs not in registry)
43	    const raw = base.PATH ?? base.Path ?? "";
44	    if (FULL_SYSTEM_PATH) {
45	      const existing = new Set(raw.split(";").map(p => p.toLowerCase()));
46	      const extras = FULL_SYSTEM_PATH.split(";").filter(p => p && !existing.has(p.toLowerCase()));
47	      if (extras.length) base.PATH = raw + ";" + extras.join(";");
48	    }
49	  }
50	
51	  // Diagnostic: log once on first call
52	  if (process.platform === "win32" && !_spawnEnvLogged) {
53	    _spawnEnvLogged = true;
54	    console.log(`[buildSpawnEnv] RAW process.env.PATH=${process.env.PATH ?? "undefined"}`);
55	    console.log(`[buildSpawnEnv] RAW process.env.Path=${process.env.Path ?? "undefined"}`);
56	    console.log(`[buildSpawnEnv] FINAL PATH=${base.PATH}`);
57	    console.log(`[buildSpawnEnv] COMSPEC=${base.COMSPEC}`);
58	    console.log(`[buildSpawnEnv] SystemRoot=${base.SystemRoot}`);
59	  }
60	
61	  return base;
62	}
