64	/**
65	 * Minimal ACP (Agent Client Protocol) client that speaks JSON-RPC 2.0
66	 * over the agent subprocess' stdio. One AcpClient == one agent process
67	 * == one conversation session (we only use session/new once).
68	 *
69	 * Framing: auto-detected per peer message. We support both
70	 *   - line-delimited JSON (one JSON object per line, ACP reference servers)
71	 *   - LSP-style Content-Length headers (used by some implementations)
72	 * Our outbound framing mirrors whatever the agent first used; until then
73	 * we default to line-delimited JSON.
74	 *
75	 * Spec references:
76	 *   https://agentclientprotocol.com/protocol/overview
77	 *   https://agentclientprotocol.com/protocol/initialization
78	 *   https://agentclientprotocol.com/protocol/session-setup
79	 *   https://agentclientprotocol.com/protocol/prompt-turn
80	 */
81	
82	type JsonRpcId = number | string;
83	
84	interface JsonRpcRequest {
85	  jsonrpc: "2.0";
86	  id: JsonRpcId;
87	  method: string;
88	  params?: unknown;
89	}
90	
91	interface JsonRpcResponse {
92	  jsonrpc: "2.0";
93	  id: JsonRpcId;
94	  result?: unknown;
95	  error?: { code: number; message: string; data?: unknown };
96	}
97	
98	interface JsonRpcNotification {
99	  jsonrpc: "2.0";
100	  method: string;
101	  params?: unknown;
102	}
103	
104	type JsonRpcMessage = JsonRpcRequest | JsonRpcResponse | JsonRpcNotification;
105	
106	export interface SessionUpdate {
107	  sessionId: string;
108	  update: {
109	    sessionUpdate: string;
110	    [k: string]: unknown;
111	  };
112	}
113	
114	export interface AcpClientOptions {
115	  command: string;
116	  args: string[];
117	  cwd: string;
118	  env?: NodeJS.ProcessEnv;
119	  /**
120	   * Permission policy for agent-initiated `session/request_permission`.
121	   * "grant-all" (default): auto-allow everything — the bridge's normal
122	   * fully-open mode. "readonly": deny tool calls whose kind mutates state
123	   * (edit/delete/move/execute) — used by MoA reference advisors. Note this
124	   * only bites when the agent actually asks; harnesses running with
125	   * auto-approve (kiro `-a`) never send permission requests.
126	   */
127	  permissionMode?: "grant-all" | "readonly";
128	  /**
129	   * How many times to retry `prompt()` when the agent reports a transient
130	   * backend error (e.g. AWS Bedrock "dispatch failure" mid-stream).
131	   * 0 = no retries. Default 2.
132	   */
133	  promptRetries?: number;
134	  /**
135	   * Initial backoff (ms) before the first retry. Doubled each attempt.
136	   * Default 1000.
137	   */
138	  promptRetryBaseMs?: number;
139	  /**
140	   * Pin the ACP session's model right after session/new via
141	   * `session/set_config_option`. Accepts the adapter's canonical model id or a
142	   * fuzzy alias (e.g. "fable-5"). Only adapters that expose a "model" config
143	   * option (currently claude-agent-acp) honour it; others reject and we log.
144	   * Empty/undefined = leave the agent's own default untouched.
145	   */
146	  acpModel?: string;
147	  /**
148	   * Pin the session's reasoning effort (e.g. "low"/"medium"/"high") after the
149	   * model is set. Must exactly match a value the selected model supports —
150	   * unlike model, there is no fuzzy fallback. Empty/undefined = untouched.
151	   */
152	  acpEffort?: string;
153	}
154	
155	/**
156	 * Errors where the agent's cloud backend aborted the response stream. These
157	 * are almost always worth retrying (network blip, TLS reset, 5xx from the
158	 * upstream provider). We detect by error code + message/data fingerprints,
159	 * since kiro-cli wraps them as generic JSON-RPC -32603 Internal error.
160	 */
161	function isTransientBackendError(err: unknown): boolean {
162	  if (!err || typeof err !== "object") return false;
163	  const e = err as { code?: number; message?: string; data?: unknown };
164	  if (e.code !== -32603) return false;
165	  const parts: string[] = [];
166	  if (typeof e.message === "string") parts.push(e.message);
167	  if (e.data !== undefined) {
168	    try {
169	      parts.push(typeof e.data === "string" ? e.data : JSON.stringify(e.data));
170	    } catch {
171	      /* ignore */
172	    }
173	  }
174	  const blob = parts.join(" ").toLowerCase();
175	  return (
176	    blob.includes("dispatch failure") ||
177	    blob.includes("response stream") ||
178	    blob.includes("timeout") ||
179	    blob.includes("connection reset") ||
180	    blob.includes("connection closed") ||
181	    blob.includes("broken pipe")
182	  );
183	}
184	
185	type Framing = "line" | "lsp";
186	
187	export declare interface AcpClient {
188	  on(event: "update", listener: (u: SessionUpdate) => void): this;
189	  on(event: "exit", listener: (code: number | null) => void): this;
190	  on(event: "stderr", listener: (chunk: string) => void): this;
191	  on(event: "request", listener: (req: JsonRpcRequest) => void): this;
192	}
193	
194	export class AcpClient extends EventEmitter {
195	  private proc: ChildProcessWithoutNullStreams;
196	  private nextId = 1;
197	  private pending = new Map<
198	    JsonRpcId,
199	    { resolve: (v: unknown) => void; reject: (e: Error) => void }
200	  >();
201	  /** Incoming bytes, kept as Buffer because LSP framing needs byte counts. */
202	  private inBuf: Buffer = Buffer.alloc(0);
203	  /** Outbound framing. Flipped to the peer's framing once we see one. */
204	  private outFraming: Framing = "line";
205	  /** Set once we've positively identified the peer's framing. */
206	  private framingLocked = false;
207	  private sessionId: string | null = null;
208	  private closed = false;
209	  /** Protocol-level JSON-RPC tracer; set once the session id is known. */
210	  private _tracer: AcpTracer | null = null;
211	  /** initialize 回應宣告的 agent capabilities（session/load 前置檢查用）。 */
212	  private agentCapabilities: { loadSession?: boolean } = {};
213	  /**
214	   * session/load replay 抑制旗標。載入歷史時 agent 會以 session/update
215	   * 重播整段對話 —— 這些 update 不可外流（會重觸發 <<ASK>>/<<SCHEDULE>>
216	   * 等 token 副作用）。session/load 回應解決後關閉。
217	   */
218	  private replaying = false;
219	
220	  /** ACP protocol tracer (null until session/new completes). */
221	  get tracer(): AcpTracer | null {
222	    return this._tracer;
223	  }
224	
225	  /** Subprocess PID for health monitoring. */
226	  get pid(): number | undefined {
227	    return this.proc?.pid;
228	  }
229	
230	  /**
231	   * On Windows, batch files (.bat/.cmd) and PowerShell scripts (.ps1) can't
232	   * be launched directly by CreateProcess — they need a shell interpreter.
233	   * Bare commands without an extension (e.g. "kiro-cli", "npx") also need
234	   * the shell so PATHEXT can resolve them to the right .cmd/.exe shim.
235	   * On POSIX we never need shell (the kernel handles shebangs).
236	   */
237	  private static commandNeedsShell(command: string): boolean {
238	    if (process.platform !== "win32") return false;
239	    const trimmed = command.trim();
240	    if (/\.(?:bat|cmd|ps1)$/i.test(trimmed)) return true;
241	    // If the command has no extension, let cmd.exe resolve it via PATHEXT.
242	    // node.exe, foo.exe and absolute paths to .exe files don't need a shell.
243	    const base = trimmed.replace(/^.*[\\/]/, "");
244	    return !/\.[^.\\/]+$/.test(base);
245	  }
246	
247	  /**
248	   * Quote a token for cmd.exe. We only need to handle the common cases:
249	   * values with spaces, and values with embedded double quotes. cmd.exe's
250	   * quoting rules are primitive — wrap in double quotes and escape any
251	   * embedded quotes by doubling them.
252	   */
253	  private static quoteForShell(token: string): string {
254	    if (token === "") return '""';
255	    if (!/[\s"&|<>^()]/.test(token)) return token;
256	    return `"${token.replace(/"/g, '""')}"`;
257	  }
258	
259	  constructor(private opts: AcpClientOptions) {
260	    super();
261	    // On Windows, CreateProcess can't launch .bat/.cmd/.ps1 directly, so we
262	    // need a shell for those. Everything else (node, npx.exe, a real .exe)
263	    // can be spawned without a shell — which avoids Node's DEP0190 warning
264	    // about passing args alongside `shell: true` and also sidesteps any
265	    // shell-quoting surprises in the args array.
266	    const needsShell = AcpClient.commandNeedsShell(opts.command);
267	    if (needsShell) {
268	      // When shell is required, build a single quoted command string and
269	      // pass empty args — that's the API shape Node wants post-DEP0190.
270	      const cmdLine = [opts.command, ...opts.args]
271	        .map(AcpClient.quoteForShell)
272	        .join(" ");
273	      this.proc = spawn(cmdLine, [], {
274	        cwd: opts.cwd,
275	        env: buildSpawnEnv(opts.env),
276	        stdio: ["pipe", "pipe", "pipe"],
277	        shell: true,
278	      });
279	    } else {
280	      this.proc = spawn(opts.command, opts.args, {
281	        cwd: opts.cwd,
282	        env: buildSpawnEnv(opts.env),
283	        stdio: ["pipe", "pipe", "pipe"],
284	      });
285	    }
286	
287	    // Keep stdout as Buffer so LSP byte-length framing works correctly.
288	    this.proc.stderr.setEncoding("utf8");
289	
290	    this.proc.stdout.on("data", (chunk: Buffer) => this.onStdout(chunk));
291	    this.proc.stderr.on("data", (chunk: string) => this.emit("stderr", chunk));
292	    this.proc.on("exit", (code) => {
293	      this.closed = true;
294	      for (const { reject } of this.pending.values()) {
295	        reject(new Error(`ACP agent exited with code ${code}`));
296	      }
297	      this.pending.clear();
298	      this.emit("exit", code);
299	    });
300	    this.proc.on("error", (err) => {
301	      this.emit("stderr", `spawn error: ${err.message}\n`);
302	    });
303	  }
304	
305	  private onStdout(chunk: Buffer) {
306	    this.inBuf = this.inBuf.length === 0 ? chunk : Buffer.concat([this.inBuf, chunk]);
307	    // Keep draining: either LSP framed messages or newline-terminated JSON.
308	    for (;;) {
309	      const consumed = this.tryReadOne();
310	      if (!consumed) break;
311	    }
312	  }
313	
314	  /**
315	   * Try to read one full JSON-RPC message from the buffer.
316	   * Returns true if a message was consumed (loop again), false otherwise.
317	   */
318	  private tryReadOne(): boolean {
319	    if (this.inBuf.length === 0) return false;
320	
321	    // 1) LSP framing starts with "Content-Length:".
322	    //    Peek first few bytes; if they look like a header, parse it.
323	    if (this.looksLikeLspHeader()) {
324	      return this.tryReadLsp();
325	    }
326	
327	    // 2) Otherwise treat as line-delimited JSON.
328	    const nl = this.inBuf.indexOf(0x0a); // "\n"
329	    if (nl < 0) return false;
330	
331	    const lineBytes = this.inBuf.subarray(0, nl);
332	    this.inBuf = this.inBuf.subarray(nl + 1);
333	    const line = lineBytes.toString("utf8").trim();
334	    if (!line) return true; // blank line; keep draining
335	
336	    this.tryDispatchJson(line, "line");
337	    return true;
338	  }
339	
340	  private looksLikeLspHeader(): boolean {
341	    // Fast path: "Content-Length:" is 15 bytes. Check case-insensitively
342	    // without allocating a big string.
343	    if (this.inBuf.length < 16) return false;
344	    const head = this.inBuf.subarray(0, 15).toString("ascii").toLowerCase();
345	    return head === "content-length:";
346	  }
347	
348	  private tryReadLsp(): boolean {
349	    // Find end of headers: "\r\n\r\n" (preferred) or "\n\n" as tolerance.
350	    const crlf = this.inBuf.indexOf("\r\n\r\n");
351	    const lf = this.inBuf.indexOf("\n\n");
352	    let headerEnd = -1;
353	    let sep = 0;
354	    if (crlf >= 0 && (lf < 0 || crlf < lf)) {
355	      headerEnd = crlf;
356	      sep = 4;
357	    } else if (lf >= 0) {
358	      headerEnd = lf;
359	      sep = 2;
360	    } else {
361	      return false; // headers not complete yet
362	    }
363	
364	    const headerText = this.inBuf.subarray(0, headerEnd).toString("utf8");
365	    const match = /content-length:\s*(\d+)/i.exec(headerText);
366	    if (!match) {
367	      // Malformed header line; drop it and resync.
368	      this.inBuf = this.inBuf.subarray(headerEnd + sep);
369	      this.emit("stderr", `[acp] malformed LSP header: ${headerText}\n`);
370	      return true;
371	    }
372	    const length = Number(match[1]);
373	    const totalNeeded = headerEnd + sep + length;
374	    if (this.inBuf.length < totalNeeded) return false;
375	
376	    const body = this.inBuf
377	      .subarray(headerEnd + sep, totalNeeded)
378	      .toString("utf8");
379	    this.inBuf = this.inBuf.subarray(totalNeeded);
380	    this.tryDispatchJson(body, "lsp");
381	    return true;
382	  }
383	
384	  private tryDispatchJson(raw: string, framing: Framing) {
385	    let msg: JsonRpcMessage;
386	    try {
387	      msg = JSON.parse(raw);
388	    } catch {
389	      this.emit("stderr", `[acp] non-JSON message (${framing}): ${raw}\n`);
390	      return;
391	    }
392	    if (!this.framingLocked) {
393	      this.outFraming = framing;
394	      this.framingLocked = true;
395	    }
396	    this.handleMessage(msg);
397	  }
398	
399	  private handleMessage(msg: JsonRpcMessage) {
400	    this._tracer?.logRecv(msg);
401	    if ("id" in msg && ("result" in msg || "error" in msg)) {
402	      const entry = this.pending.get(msg.id);
403	      if (!entry) return;
404	      this.pending.delete(msg.id);
405	      if (msg.error) {
406	        let detail = "";
407	        if (msg.error.data !== undefined) {
408	          try {
409	            const s =
410	              typeof msg.error.data === "string"
411	                ? msg.error.data
412	                : JSON.stringify(msg.error.data);
413	            if (s && s !== "{}" && s !== "null") detail = ` (${s})`;
414	          } catch {
415	            /* ignore stringify errors */
416	          }
417	        }
418	        const err = new Error(
419	          `${msg.error.code}: ${msg.error.message}${detail}`
420	        ) as Error & { code?: number; data?: unknown };
421	        err.code = msg.error.code;
422	        err.data = msg.error.data;
423	        entry.reject(err);
424	      } else {
425	        entry.resolve(msg.result);
426	      }
427	      return;
428	    }
429	
430	    if ("method" in msg && "id" in msg) {
431	      // Agent -> Client request (e.g. session/request_permission, fs/*).
432	      // We auto-reply with permissive defaults to keep things moving.
433	      this.emit("request", msg as JsonRpcRequest);
434	      this.handleAgentRequest(msg as JsonRpcRequest);
435	      return;
436	    }
437	
438	    if ("method" in msg) {
439	      // Notification
440	      if (msg.method === "session/update") {
441	        if (this.replaying) return; // replay 抑制（BC-2）
442	        this.emit("update", msg.params as SessionUpdate);
443	      }
444	      return;
445	    }
446	  }
447	
448	  private handleAgentRequest(req: JsonRpcRequest) {
449	    // The user wants "fully open" access, so we grant any permission
450	    // request and return empty for anything else we don't implement.
451	    if (req.method === "session/request_permission") {
452	      const params = (req.params ?? {}) as {
453	        toolCall?: { kind?: string; title?: string };
454	        options?: { optionId: string; name?: string; kind?: string }[];
455	      };
456	      if (this.opts.permissionMode === "readonly") {
457	        const kind = params.toolCall?.kind ?? "";
458	        const MUTATING = new Set(["edit", "delete", "move", "execute"]);
459	        if (MUTATING.has(kind)) {
460	          const reject =
461	            params.options?.find((o) => o.kind === "reject_always") ??
462	            params.options?.find((o) => o.kind === "reject_once");
463	          console.warn(
464	            `[acp] readonly mode denied "${kind}" tool call (${params.toolCall?.title ?? "?"})`);
465	          this.sendResponse(req.id, reject
466	            ? { outcome: { outcome: "selected", optionId: reject.optionId } }
467	            : { outcome: { outcome: "cancelled" } });
468	          return;
469	        }
470	      }
471	      const allow =
472	        params.options?.find((o) => o.kind === "allow_always") ??
473	        params.options?.find((o) => o.kind === "allow_once") ??
474	        params.options?.[0];
475	      this.sendResponse(req.id, {
476	        outcome: {
477	          outcome: "selected",
478	          optionId: allow?.optionId ?? "allow",
479	        },
480	      });
481	      return;
482	    }
483	    // Fallback: respond with an empty object so the agent isn't stuck.
484	    this.sendResponse(req.id, {});
485	  }
486	
487	  private writeMessage(obj: unknown) {
488	    if (this.closed) throw new Error("ACP agent has exited");
489	    this._tracer?.logSend(obj);
490	    const payload = JSON.stringify(obj);
491	    if (this.outFraming === "lsp") {
492	      const body = Buffer.from(payload, "utf8");
493	      const header = `Content-Length: ${body.length}\r\n\r\n`;
494	      this.proc.stdin.write(header);
495	      this.proc.stdin.write(body);
496	    } else {
497	      this.proc.stdin.write(payload + "\n");
498	    }
499	  }
500	
501	  private sendResponse(id: JsonRpcId, result: unknown) {
502	    this.writeMessage({ jsonrpc: "2.0", id, result });
503	  }
504	
505	  private call<T = unknown>(method: string, params?: unknown): Promise<T> {
506	    const id = this.nextId++;
507	    return new Promise<T>((resolve, reject) => {
508	      this.pending.set(id, {
509	        resolve: (v) => resolve(v as T),
510	        reject,
511	      });
512	      this.writeMessage({ jsonrpc: "2.0", id, method, params });
513	    });
514	  }
515	
516	  async initializeAndCreateSession(cwd: string, mcpServers?: any[]): Promise<string> {
517	    const { sessionId } = await this.initializeOrLoadSession(cwd, mcpServers);
518	    return sessionId;
519	  }
520	
521	  /**
522	   * initialize 後建立或恢復 session。
523	   * resumeSessionId 有值且 agent 宣告 loadSession capability 時先試
524	   * session/load（成功 → resumed:true，跳過 applyModelEffort——session
525	   * 內已有 model 狀態）；capability 缺失或 load 失敗一律 fallback 到
526	   * session/new（同一 subprocess，不重 spawn）。
527	   */
528	  async initializeOrLoadSession(
529	    cwd: string,
530	    mcpServers?: any[],
531	    resumeSessionId?: string,
532	  ): Promise<{ sessionId: string; resumed: boolean }> {
533	    const initRes = await this.call<{ agentCapabilities?: { loadSession?: boolean } }>("initialize", {
534	      protocolVersion: 1,
535	      clientCapabilities: {
536	        fs: { readTextFile: true, writeTextFile: true },
537	        terminal: true,
538	      },
539	      clientInfo: {
540	        name: "telegram-kiro-bridge",
541	        title: "Telegram ↔ Kiro Bridge",
542	        version: "0.1.0",
543	      },
544	    });
545	    this.agentCapabilities = initRes?.agentCapabilities ?? {};
546	
547	    if (resumeSessionId && this.agentCapabilities.loadSession === true) {
548	      this.replaying = true;
549	      try {
550	        await this.call("session/load", {
551	          sessionId: resumeSessionId,
552	          cwd,
553	          mcpServers: mcpServers ?? [],
554	        });
555	        this.sessionId = resumeSessionId;
556	        this._tracer = new AcpTracer(resumeSessionId);
557	        return { sessionId: resumeSessionId, resumed: true };
558	      } catch (err) {
559	        this.emit("stderr", `[acp] session/load failed, falling back to session/new: ${(err as Error).message}\n`);
560	      } finally {
561	        this.replaying = false;
562	      }
563	    }
564	
565	    const res = await this.call<{ sessionId: string }>("session/new", {
566	      cwd,
567	      mcpServers: mcpServers ?? [],
568	    });
569	    this.sessionId = res.sessionId;
570	    this._tracer = new AcpTracer(res.sessionId);
571	    await this.applyModelEffort();
572	    return { sessionId: res.sessionId, resumed: false };
573	  }
574	
575	  /**
576	   * Pin model and/or effort on the freshly-created session via the ACP
577	   * `session/set_config_option` request (read from opts.acpModel/acpEffort).
578	   *
579	   * Best-effort: any failure (adapter doesn't support the method, invalid
580	   * value, dead stream) is logged to stderr and swallowed so it can never
581	   * abort session startup. No-op when neither option is configured, which is
582	   * the case for every ephemeral call site (scheduler / specialist /
583	   * daily-intel / session-extract) — only the main interactive session wires
584	   * these through, so their behaviour is unchanged.
585	   *
586	   * Model is applied before effort because the adapter rebuilds the effort
587	   * option list from the selected model (effort levels are model-specific).
588	   */
589	  private async applyModelEffort(): Promise<void> {
590	    const model = (this.opts.acpModel ?? "").trim();
591	    const effort = (this.opts.acpEffort ?? "").trim();
592	    if (!model && !effort) return;
593	    if (!this.sessionId) return;
594	
595	    const set = async (configId: string, value: string) => {
596	      try {
597	        await this.call("session/set_config_option", {
598	          sessionId: this.sessionId,
599	          configId,
600	          value,
601	        });
602	        this.emit("stderr", `[acp] pinned ${configId}=${value}\n`);
603	      } catch (err) {
604	        const msg = (err as Error).message ?? String(err);
605	        this.emit(
606	          "stderr",
607	          `[acp] set ${configId}=${value} not applied (ignored): ${msg}\n`,
608	        );
609	      }
610	    };
611	
612	    if (model) await set("model", model);
613	    if (effort) await set("effort", effort);
614	  }
615	
616	  /**
617	   * Send a user prompt and wait for the turn to end.
618	   * Text chunks streamed by the agent are delivered via "update" events.
619	   *
620	   * Automatically retries transient backend errors (see
621	   * isTransientBackendError) up to `opts.promptRetries` times with
622	   * exponential backoff. Retries are NOT attempted once the agent process
623	   * has exited — the caller needs to spin up a new session for that.
624	   */
625	  async prompt(text: string): Promise<{ stopReason: string }> {
626	    if (!this.sessionId) throw new Error("Session not initialized");
627	    const maxRetries = this.opts.promptRetries ?? 2;
628	    const baseMs = this.opts.promptRetryBaseMs ?? 1000;
629	    let attempt = 0;
630	    for (;;) {
631	      try {
632	        return await this.call<{ stopReason: string }>("session/prompt", {
633	          sessionId: this.sessionId,
634	          prompt: [{ type: "text", text }],
635	        });
636	      } catch (err) {
637	        const retriable =
638	          !this.closed &&
639	          attempt < maxRetries &&
640	          isTransientBackendError(err);
641	        if (!retriable) throw err;
642	        const delayMs = baseMs * Math.pow(2, attempt);
643	        const msg = (err as Error).message ?? String(err);
644	        this.emit(
645	          "stderr",
646	          `[acp] transient backend error, retrying in ${delayMs}ms ` +
647	            `(attempt ${attempt + 1}/${maxRetries}): ${msg}\n`,
648	        );
649	        await new Promise((r) => setTimeout(r, delayMs));
650	        attempt++;
651	      }
652	    }
653	  }
654	
655	  cancel() {
656	    if (!this.sessionId || this.closed) return;
657	    this.writeMessage({
658	      jsonrpc: "2.0",
659	      method: "session/cancel",
660	      params: { sessionId: this.sessionId },
661	    });
662	  }
663	
664	  async close() {
665	    if (this.closed) return;
666	    try {
667	      this.proc.stdin.end();
668	    } catch {
669	      /* noop */
670	    }
671	    // On Windows, proc.kill() only kills the direct child (e.g. cmd.exe),
672	    // leaving grandchildren (electron, long-running tools) alive as orphans.
673	    // Use taskkill /T to kill the entire process tree.
674	    if (process.platform === "win32" && this.proc.pid) {
675	      try {
676	        execSync(`taskkill /T /F /PID ${this.proc.pid}`, { stdio: "ignore" });
677	      } catch {
678	        this.proc.kill(); // fallback
679	      }
680	    } else {
681	      this.proc.kill();
682	    }
683	  }
684	
685	  get isClosed() {
686	    return this.closed;
687	  }
688	}
