267	// askTimeKeyToWire / describePendingSchedule
268	// ---------------------------------------------------------------------------
269	export function askTimeKeyToWire(kind: PendingSchedule["kind"], key: string): string | null {
270	  if (kind === "add" || kind === "every") {
271	    return /^\d+(s|m|h|d)$/.test(key) ? key : null;
272	  }
273	  const mDirect = /^(\d{2})(\d{2})$/.exec(key);
274	  if (mDirect) return `${mDirect[1]}:${mDirect[2]}`;
275	  if (kind === "at") {
276	    const mTmr = /^tmr_(\d{2})(\d{2})$/.exec(key);
277	    if (mTmr) return `tomorrow ${mTmr[1]}:${mTmr[2]}`;
278	  }
279	  return null;
280	}
