282	export function describePendingSchedule(kind: PendingSchedule["kind"], time: string): string {
283	  switch (kind) {
284	    case "add":   return `${time} 後（一次性）`;
285	    case "at":    return `${time}（一次性）`;
286	    case "every": return `每 ${time}`;
287	    case "daily": return `每天 ${time}`;
288	  }
289	}
