350	// ---------------------------------------------------------------------------
351	// splitForTelegram
352	// ---------------------------------------------------------------------------
353	export function splitForTelegram(text: string, max = TG_MAX): string[] {
354	  if (text.length <= max) return [text];
355	  const raw: string[] = [];
356	  let rest = text;
357	  while (rest.length > max) {
358	    let cut = rest.lastIndexOf("\n\n", max);
359	    if (cut < max * 0.5) cut = rest.lastIndexOf("\n", max);
360	    if (cut < max * 0.5) cut = rest.lastIndexOf(" ", max);
361	    if (cut <= 0) cut = max;
362	    raw.push(rest.slice(0, cut));
363	    rest = rest.slice(cut).replace(/^[\n ]+/, "");
364	  }
365	  if (rest.length) raw.push(rest);
366	
367	  const fenceRe = /^```([^\n`]*)\s*$/;
368	  const out: string[] = [];
369	  let openLang = "";
370	  for (let i = 0; i < raw.length; i++) {
371	    let piece = raw[i];
372	    if (openLang !== "") {
373	      piece = "```" + openLang + "\n" + piece;
374	    }
375	    const lines = piece.split("\n");
376	    let inside = false;
377	    let lang = "";
378	    for (const line of lines) {
379	      const m = line.match(fenceRe);
380	      if (!m) continue;
381	      if (!inside) {
382	        inside = true;
383	        lang = m[1] ?? "";
384	      } else {
385	        inside = false;
386	        lang = "";
387	      }
388	    }
389	    if (inside && i < raw.length - 1) {
390	      piece = piece + (piece.endsWith("\n") ? "" : "\n") + "```";
391	      openLang = lang;
392	    } else {
393	      openLang = "";
394	    }
395	    out.push(piece);
396	  }
397	  return out;
398	}
