303	    const text = truncate(`${header}\n\n${body}`, 3800);
304	    try {
305	      await this.bot.api.sendMessage(entry.chatId, text);
306	    } catch (err) {
307	      console.error(`${tag} sendMessage to ${entry.chatId} failed:`, err);
308	    }
309	
310	    return this.afterFire(entry, result, tag);
311	  }
312	
313	  /**
314	   * Shared tail for fire(): recurring re-arm + onFire callback. Called from
315	   * both the bridge-command branch and the AcpClient branch so their re-arm
316	   * behaviour stays identical.
317	   */
318	  private async afterFire(
319	    entry: ScheduleEntry,
320	    result: FireResult,
321	    tag: string,
322	  ): Promise<FireResult> {
323	    // Recurring: compute next tick, update in-memory entry, persist, re-arm.
324	    // If computeNextRunAt returns null (e.g. cron became unsatisfiable after
325	    // a DST transition, recurrence fields are corrupted, or from/next came
326	    // out non-finite) drop the entry so it doesn't loop.
327	    if (entry.recurrence) {
328	      const next = computeNextRunAt(entry.recurrence, entry.runAt);
329	      if (next === null || !Number.isFinite(next)) {
330	        console.warn(
331	          `${tag} recurrence produced no usable next tick (next=${next}); removing entry`,
332	        );
333	        this.store.forgetInMemory(entry.id);
334	        await this.store.persist().catch((err) =>
335	          console.error(`${tag} persist after drop failed:`, err),
336	        );
337	        // Tell the user so a silently-dropped recurring schedule doesn't
338	        // surprise them. Non-finite next implies corrupted recurrence data;
339	        // a human needs to re-create the schedule with a valid spec.
340	        const msg =
341	          `⚠️ 排程 ${entry.id}（${formatRecurrence(entry.recurrence)}）已被移除：` +
342	          `無法計算下次觸發時間（next=${next}）。\n` +
343	          `可能是 recurrence 欄位不完整或 cron 無解。請重跑 /schedule 重新建立。`;
344	        await this.bot.api.sendMessage(entry.chatId, msg).catch((err) =>
345	          console.error(`${tag} notify drop failed:`, err),
346	        );
347	      } else {
348	        const live = this.store.get(entry.id);
349	        if (live) {
350	          live.runAt = next;
351	          await this.store.persist().catch((err) =>
352	            console.error(`${tag} persist next tick failed:`, err),
353	          );
354	          this.arm(live);
355	          console.log(
356	            `${tag} next tick at ${new Date(next).toLocaleString()} (${formatRecurrence(entry.recurrence)})`,
357	          );
358	        }
359	      }
360	    }
361	
362	    this.options.onFire?.(entry, result);
363	    return result;
364	  }
365	}
