1	/**
2	 * 非同步呼叫合併器（coalescing runner）。
3	 *
4	 * 把一個 async fn 包成「同一時間最多一個 in-flight」的 runner：
5	 * - 進行中再被呼叫 → 標記 pending，立即返回（不排隊、不並發）
6	 * - 當前執行結束後若有 pending → 補跑一次（拿到最新狀態即可，中間的呼叫合併掉）
7	 * - isCancelled() 為 true → 不啟動、也不補跑
8	 *
9	 * 動機（2026-07-11 roadmap 事故）：streaming 的 editNow 被 onUpdate（每
10	 * chunk）/ keepalive / rate-limit recovery 多路觸發，且節流時間戳只在成功
11	 * 後更新——送出一旦開始失敗，時間閘門全開，並發呼叫在「draft 失敗 →
12	 * !placeholder → sendMessage」的降級分支各自建立 placeholder，一口氣冒出
13	 * 十幾則相同內容的訊息。latch 讓降級分支天然序列化，TOCTOU 消失。
14	 */
15	export function coalesceAsyncRunner(
16	  fn: () => Promise<void>,
17	  isCancelled: () => boolean = () => false,
18	): () => Promise<void> {
19	  let inFlight = false;
20	  let pending = false;
21	  const run = async (): Promise<void> => {
22	    if (isCancelled()) return;
23	    if (inFlight) {
24	      pending = true;
25	      return;
26	    }
27	    inFlight = true;
28	    try {
29	      await fn();
30	    } finally {
31	      inFlight = false;
32	      if (pending) {
33	        pending = false;
34	        if (!isCancelled()) void run();
35	      }
36	    }
37	  };
38	  return run;
39	}
