211	/** Send a file to another bot via Telegram bot-to-bot (telegram/both transport only). */
212	export async function sendRelayFile(targetBot: string, filePath: string, caption: string = "[RELAY_INPUT]"): Promise<boolean> {
213	  if (!cfg || !bot) return false;
214	  if (process.env.RELAY_PAUSED === "true") {
215	    console.log(`[relay] RELAY_PAUSED — blocked outgoing file to "${targetBot}"`);
216	    return false;
217	  }
218	  if (targetBot === cfg.botName) {
219	    console.warn(`[relay] blocked self-send file (target="${targetBot}")`);
220	    return false;
221	  }
222	  const abs = path.resolve(filePath);
223	  if (!isUnderAllowedRoot(abs)) {
224	    console.warn(`[relay] blocked file outside allowed roots to "${targetBot}": ${abs}`);
225	    return false;
226	  }
227	  let st;
228	  try {
229	    st = await stat(abs);
230	  } catch (err) {
231	    console.warn(`[relay] sendRelayFile stat failed for ${abs}:`, (err as Error).message);
232	    return false;
233	  }
234	  if (!st.isFile()) {
235	    console.warn(`[relay] blocked non-file relay attachment to "${targetBot}": ${abs}`);
236	    return false;
237	  }
238	  const transport = cfg.transport;
239	  if (transport === "redis") {
240	    console.warn(`[relay] sendRelayFile requires telegram transport, current=${transport}`);
241	    return false;
242	  }
243	  const target = cfg.targetBotUsername;
244	  if (!target) {
245	    console.warn(`[relay] sendRelayFile: no targetBotUsername configured`);
246	    return false;
247	  }
248	  try {
249	    const ext = path.extname(abs).toLowerCase();
250	    // RELAY_OUTPUT with PNG: send as document to preserve transparency.
251	    // RELAY_INPUT: send as photo (compression OK for reference images).
252	    const isOutput = caption === "[RELAY_OUTPUT]";
253	    const asPhoto = IMG_EXT.has(ext) && st.size <= PHOTO_MAX_BYTES && !(isOutput && ext === ".png");
254	    if (asPhoto) {
255	      await bot.api.sendPhoto(target, new InputFile(abs), { caption });
256	    } else {
257	      await bot.api.sendDocument(target, new InputFile(abs), { caption });
258	    }
259	    console.log(`[relay] ✓ sent file via TELEGRAM to ${target}: ${abs}`);
260	    await bot.api.sendMessage(cfg.groupChatId, `📤🖼️ [${cfg.botName} -> ${targetBot}] file: ${abs}`).catch(() => {});
261	    return true;
262	  } catch (err) {
263	    console.error(`[relay] sendRelayFile to ${target} failed:`, err);
264	    return false;
265	  }
266	}
