298	/** Initialize relay (registers config + handler). Poller activates on demand. */
299	export function startRelayPoller(
300	  botInstance: Bot,
301	  relayConfig: RelayConfig,
302	  handler: (msg: RelayMessage) => void,
303	): void {
304	  cfg = relayConfig;
305	  bot = botInstance;
306	  onIncoming = handler;
307	  if (pollTimer) { clearInterval(pollTimer); pollTimer = null; }
308	  if (heartbeatTimer) { clearInterval(heartbeatTimer); heartbeatTimer = null; }
309	  // Skip Redis polling entirely when transport is telegram-only.
310	  if (relayConfig.transport === "telegram") {
311	    console.log(`[relay] ready - transport=telegram (${describeRelayTransport(relayConfig.transport)}), Redis poller intentionally disabled`);
312	    return;
313	  }
314	  // Low-freq heartbeat: check for unsolicited incoming every 30s.
315	  heartbeatTimer = setInterval(() => {
316	    if (!pollTimer) poll(); // only if high-freq poller is not running
317	  }, HEARTBEAT_MS);
318	  // One immediate poll to drain anything queued while offline.
319	  poll();
320	  console.log(`[relay] ready - heartbeat every ${HEARTBEAT_MS / 1000}s, high-freq poller on demand (key="${redisKey(cfg.botName)}")`);
321	}
