350	// ─── Dedup for "both" mode ─────────────────────────────────────────────────
351	const recentHashes = new Set<string>();
352	const DEDUP_TTL_MS = 10_000;
353	
354	function dedupKey(from: string, text: string): string {
355	  // Simple hash: first 100 chars of text + sender
356	  return `${from}:${text.slice(0, 100)}`;
357	}
