388	// ─── Structured Delegation Protocol ────────────────────────────────────────
389	export const DELEGATE_PREFIX = "[RELAY_DELEGATE]";
390	export const RESULT_PREFIX = "[RELAY_RESULT]";
391	
392	export interface DelegatePayload {
393	  id: string;          // correlation_id
394	  goal: string;
395	  context?: string;
396	  maxTurns?: number;
397	}
398	
399	export interface ResultPayload {
400	  id: string;          // correlation_id matching the delegation
401	  status: "done" | "failed" | "timeout";
402	  summary: string;
403	}
404	
405	/** Generate a correlation_id for delegation. */
406	export function generateCorrelationId(): string {
407	  const hex = Math.random().toString(16).slice(2, 6);
408	  return `rd_${Date.now()}_${hex}`;
409	}
410	
411	/** Send a structured delegation request via relay. */
412	export async function sendRelayDelegate(targetBot: string, payload: DelegatePayload): Promise<void> {
413	  const text = `${DELEGATE_PREFIX} ${JSON.stringify(payload)}`;
414	  await sendRelay(targetBot, text);
415	}
416	
417	/** Send a structured result back via relay. */
418	export async function sendRelayResult(targetBot: string, payload: ResultPayload): Promise<void> {
419	  const text = `${RESULT_PREFIX} ${JSON.stringify(payload)}`;
420	  await sendRelay(targetBot, text);
421	}
422	
423	/** Parse incoming relay text — returns typed payload or null (plain message). */
424	export function parseRelayPayload(text: string): 
425	  | { type: "delegate"; payload: DelegatePayload }
426	  | { type: "result"; payload: ResultPayload }
427	  | null {
428	  if (text.startsWith(DELEGATE_PREFIX)) {
429	    try {
430	      const json = JSON.parse(text.slice(DELEGATE_PREFIX.length).trim());
431	      return { type: "delegate", payload: json as DelegatePayload };
432	    } catch { return null; }
433	  }
434	  if (text.startsWith(RESULT_PREFIX)) {
435	    try {
436	      const json = JSON.parse(text.slice(RESULT_PREFIX.length).trim());
437	      return { type: "result", payload: json as ResultPayload };
438	    } catch { return null; }
439	  }
440	  return null;
441	}
