1	/**
2	 * Reply Dedup — 防止 specialist/parallel delegate 結果重複注入主 session。
3	 *
4	 * 機制：對每個 (chatId, summaryHash) 做 5 分鐘時間窗去重。
5	 * 如果同一個 chatId 在 5 分鐘內收到相同 summary hash 的結果，
6	 * 視為重複並跳過注入。
7	 *
8	 * 觸發場景：
9	 * - retry 邏輯導致 specialist 重跑同一任務
10	 * - goal continuation 過程中重複觸發 delegate
11	 * - 網路/timeout retry 導致結果雙重回傳
12	 */
13	import { createHash } from "node:crypto";
14	
15	const DEDUP_WINDOW_MS = 5 * 60 * 1000; // 5 分鐘
16	
17	interface DedupEntry {
18	  hash: string;
19	  timestamp: number;
20	}
21	
22	// chatId → 最近的 dedup entries
23	const _cache = new Map<number, DedupEntry[]>();
24	
25	/**
26	 * 計算文字的去重 hash（取前 2000 字做 SHA-256 前 16 hex）。
27	 * 用前 2000 字是因為 specialist summary 最長就 2000。
28	 */
29	function computeHash(text: string): string {
30	  const input = text.slice(0, 2000);
31	  return createHash("sha256").update(input, "utf8").digest("hex").slice(0, 16);
32	}
33	
34	/**
35	 * 檢查是否重複。若不重複則登記並回傳 false；若重複回傳 true。
36	 *
37	 * @param chatId — Telegram chat ID
38	 * @param summary — specialist result summary 文字
39	 * @returns true = 重複（應跳過注入）, false = 新的（可以注入）
40	 */
41	export function isDuplicateResult(chatId: number, summary: string): boolean {
42	  const now = Date.now();
43	  const hash = computeHash(summary);
44	
45	  // 取出或初始化 cache
46	  let entries = _cache.get(chatId);
47	  if (!entries) {
48	    entries = [];
49	    _cache.set(chatId, entries);
50	  }
51	
52	  // 清理過期 entries
53	  const cutoff = now - DEDUP_WINDOW_MS;
54	  const fresh = entries.filter((e) => e.timestamp > cutoff);
55	
56	  // 檢查是否有相同 hash
57	  const dup = fresh.some((e) => e.hash === hash);
58	  if (dup) {
59	    _cache.set(chatId, fresh);
60	    return true; // 重複
61	  }
62	
63	  // 登記新 entry
64	  fresh.push({ hash, timestamp: now });
65	  _cache.set(chatId, fresh);
66	  return false; // 不重複
67	}
68	
69	/**
70	 * 清除指定 chatId 的 dedup cache（例如 /reset 時）。
71	 */
72	export function clearDedupCache(chatId?: number): void {
73	  if (chatId !== undefined) {
74	    _cache.delete(chatId);
75	  } else {
76	    _cache.clear();
77	  }
78	}
